def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 3:
            base_score = 3000 + (ratio - 3) * 300
            penalty = 0
            for m in range(1, 5):
                penalty += np.sin((item * m) / (capacity + m))
            priorities[i] = base_score + penalty * 50
        elif 2 < ratio <= 3:
            priorities[i] = 1000 + (ratio - 2) * 150
            for n in range(5):
                priorities[i] -= (n + 1) * 0.1 / (capacity + 1)
        elif 1 < ratio <= 2:
            priorities[i] = 600 + (ratio - 1) * 120
            temp_score = 0
            for j in range(1, 15):
                val = ((capacity - item) ** (j/2)) / (capacity ** (j/2))
                if val < 0.03:
                    temp_score += val * 150
                elif 0.03 <= val < 0.1:
                    temp_score += val * 30 / j
                else:
                    temp_score += val * 10 / (j ** 2)
            priorities[i] += temp_score
        elif ratio == 1:
            priorities[i] = 200 + np.cos(item / (capacity + 1)) * 10
        else:
            score = 0
            for j in range(1, 20):
                temp = ((capacity - item) ** j) / (capacity ** j)
                if temp < 0.02:
                    score += temp * 200
                elif 0.02 <= temp < 0.1:
                    if j % 2 == 0:
                        score += temp * 25 / j
                    else:
                        score += temp * 15 / j
                else:
                    score += temp * 7 / (j ** 2)
            if score < 0.02:
                priorities[i] = score * 25 + np.log1p(capacity)
            elif 0.02 <= score < 0.25:
                priorities[i] = 1 / (score + 0.4) + (item / (capacity + 1)) ** 0.5
            else:
                adjustment = 0
                for k in range(1, 6):
                    adjustment += ((item / (capacity + k)) ** k) * 12 / (k + 1)
                    if k % 2 == 0:
                        adjustment -= np.sqrt(k) / (capacity + k)
                priorities[i] = 1 / (score + 1.5) + adjustment
        leftover = capacity - item
        if leftover < 0.15 * capacity:
            priorities[i] += 0.15 * leftover
            for p in range(1, 4):
                priorities[i] += (leftover ** p) / ((capacity + p) * (p + 2))
        if item > capacity * 0.85:
            priorities[i] *= 0.85 + np.tanh(item / (capacity + 0.1)) * 0.1
        if i % 3 == 0:
            priorities[i] += 1 / (capacity + 2)
            for q in range(1, 5):
                priorities[i] += np.sin(i * q) / (capacity + q)
        elif i % 3 == 1:
            priorities[i] -= 1 / (capacity + 3)
            for r in range(1, 3):
                priorities[i] -= np.cos(i * r) / (capacity + r + 1)
        else:
            priorities[i] += np.log1p(i + capacity) / (capacity + 1)
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) * 0.5 + 10
    return priorities
